import{_ as n,o as a,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"CAT-19. 물류 & SCM & 제조","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/logistics-manufacturing.md","filePath":"hermes/benchmark/logistics-manufacturing.md","lastUpdated":1781092690000}'),i={name:"hermes/benchmark/logistics-manufacturing.md"};function e(c,s,t,o,r,h){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="cat-19-물류-scm-제조" tabindex="-1">CAT-19. 물류 &amp; SCM &amp; 제조 <a class="header-anchor" href="#cat-19-물류-scm-제조" aria-label="Permalink to &quot;CAT-19. 물류 &amp; SCM &amp; 제조&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 생산 계획, 재고 관리, 품질 관리, 공급망 등 <strong>제조/물류 현장의 실무 문서</strong>를 만들 수 있는가?</p></blockquote><hr><h2 id="lm-01-생산-계획서" tabindex="-1">LM-01. 생산 계획서 ⭐⭐ <a class="header-anchor" href="#lm-01-생산-계획서" aria-label="Permalink to &quot;LM-01. 생산 계획서 :star::star:&quot;">​</a></h2><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>월간 생산 계획서를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>공장: 가전 부품 제조업 (직원 150명, 2교대)</span></span>
<span class="line"><span>제품: 3종 (모델 A: 고급형, B: 보급형, C: OEM납품용)</span></span>
<span class="line"><span>생산 능력: 일 최대 1,000개 (3종 합산, 전환 시간 포함)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4월 수요 예측:</span></span>
<span class="line"><span>- 모델 A: 8,000개 (단가 5만원, 마진 30%)</span></span>
<span class="line"><span>- 모델 B: 12,000개 (단가 2만원, 마진 15%)</span></span>
<span class="line"><span>- 모델 C: 5,000개 (단가 3만원, 마진 20%, 납기 엄수 필수)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제약 조건:</span></span>
<span class="line"><span>- 4/1~2: 공장 정기 보수 (생산 불가)</span></span>
<span class="line"><span>- 원자재 X: 4/10 입고 예정 (모델 A에만 사용, 현재 재고 3,000개분)</span></span>
<span class="line"><span>- 작업자 교대: 주간 06~14시(80명), 야간 14~22시(70명)</span></span>
<span class="line"><span>- 모델 전환 시간: 각 2시간 (하루 최대 2회 전환)</span></span>
<span class="line"><span>- 4/15: OEM 고객 납기 (모델 C 3,000개 선납)</span></span>
<span class="line"><span>- 4/20: 공휴일 (비가동)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/monthly-production-plan-april.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 월간 생산 계획표</span></span>
<span class="line"><span>   - 일별 생산 모델 &amp; 수량 배정</span></span>
<span class="line"><span>   - 교대별 할당</span></span>
<span class="line"><span>   - 전환 일정 (언제 어떤 모델로 전환)</span></span>
<span class="line"><span>   - 가동률 계산</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 우선순위 논리</span></span>
<span class="line"><span>   - 왜 이 순서로 생산하는지 근거</span></span>
<span class="line"><span>   - 납기 vs 마진 vs 재고 균형</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 리스크 &amp; 대응</span></span>
<span class="line"><span>   - 원자재 입고 지연 시 대안</span></span>
<span class="line"><span>   - 불량률 5% 가정 시 추가 생산량</span></span>
<span class="line"><span>   - 수요 변동 ±10% 시 조정 방안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. KPI</span></span>
<span class="line"><span>   - 목표 가동률, 불량률, 납기 준수율, 재고 회전율</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 일별 배정의 제약 조건 반영 (정기보수, 공휴일, 원자재)</li><li>[ ] OEM 납기(4/15) 우선 배정 여부</li><li>[ ] 모델 전환 비용 고려한 배치 최적화</li><li>[ ] 가동률 계산의 정확성</li><li>[ ] 불량률 버퍼 반영</li><li>[ ] 리스크 대응의 현실성</li></ul><hr><h2 id="lm-02-품질-관리-문서" tabindex="-1">LM-02. 품질 관리 문서 ⭐⭐ <a class="header-anchor" href="#lm-02-품질-관리-문서" aria-label="Permalink to &quot;LM-02. 품질 관리 문서 :star::star:&quot;">​</a></h2><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>제조 라인의 품질 관리 문서 세트를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제품: 식품(음료) 생산 라인</span></span>
<span class="line"><span>규제: HACCP 인증 공장, 식약처 기준 준수</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`logistics/quality-control-plan.md\` — 품질 관리 계획서</span></span>
<span class="line"><span>   - 공정별 관리 포인트 (원료 입고 → 배합 → 충진 → 살균 → 포장 → 출하)</span></span>
<span class="line"><span>   - 각 공정: 관리 항목, 기준값, 측정 방법, 측정 빈도, 담당자</span></span>
<span class="line"><span>   - 이탈 시 조치 (Stop 기준, 조치 절차, 기록)</span></span>
<span class="line"><span>   - 검사 장비 목록 &amp; 교정 주기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`logistics/haccp-checklist.md\` — HACCP 일일 점검표</span></span>
<span class="line"><span>   - CCP(중요관리점) 3개 설정 (살균 온도, 금속 검출, 냉장 온도)</span></span>
<span class="line"><span>   - 각 CCP: 한계기준, 모니터링 방법, 이탈 시 개선조치</span></span>
<span class="line"><span>   - 일일 기록 양식 (시간, 측정값, 판정, 조치, 확인자)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`logistics/nonconformance-report.md\` — 부적합 보고서 양식 &amp; 샘플</span></span>
<span class="line"><span>   - 부적합 발견 일시, 공정, 내용</span></span>
<span class="line"><span>   - 원인 분석 (5 Why 또는 특성요인도)</span></span>
<span class="line"><span>   - 시정 조치 &amp; 예방 조치</span></span>
<span class="line"><span>   - 효과 확인 &amp; 종결</span></span>
<span class="line"><span>   - 샘플: &quot;포장 라인에서 이물 검출&quot; 사례로 작성</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. \`logistics/supplier-quality-evaluation.md\` — 원료 공급업체 평가표</span></span>
<span class="line"><span>   - 평가 항목: 품질, 납기, 가격, 대응력, 인증</span></span>
<span class="line"><span>   - 점수 체계 (100점)</span></span>
<span class="line"><span>   - 등급: A(90+)/B(70~89)/C(50~69)/D(49이하)</span></span>
<span class="line"><span>   - D등급 → 거래 중단 절차</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 식품 HACCP의 CCP 설정 정확성</li><li>[ ] 공정별 관리 항목의 적절성</li><li>[ ] 부적합 보고서의 5 Why 분석 깊이</li><li>[ ] 시정/예방 조치의 구분</li><li>[ ] 공급업체 평가 항목의 현실성</li><li>[ ] 전반적으로 식품안전 관련 규정 준수</li></ul><hr><h2 id="lm-03-재고-관리-발주-시스템" tabindex="-1">LM-03. 재고 관리 &amp; 발주 시스템 ⭐⭐ <a class="header-anchor" href="#lm-03-재고-관리-발주-시스템" aria-label="Permalink to &quot;LM-03. 재고 관리 &amp; 발주 시스템 :star::star:&quot;">​</a></h2><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>재고 관리 정책과 자동 발주 기준을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: 온라인 식품 유통 (SKU 500개, 물류센터 1곳)</span></span>
<span class="line"><span>현황:</span></span>
<span class="line"><span>- 재고 부족으로 인한 품절: 월 평균 30건</span></span>
<span class="line"><span>- 과재고로 인한 폐기: 월 500만원</span></span>
<span class="line"><span>- 재고 회전율: 4.5회/년 (업계 평균 6회)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/inventory-management-policy.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 재고 분류 (ABC 분석)</span></span>
<span class="line"><span>   - A등급 (매출 상위 20% 품목): 긴밀 관리</span></span>
<span class="line"><span>   - B등급 (중간 30%): 표준 관리</span></span>
<span class="line"><span>   - C등급 (하위 50%): 간소 관리</span></span>
<span class="line"><span>   - 분류 기준 산식, 재분류 주기 (분기)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 발주 기준</span></span>
<span class="line"><span>   - 안전 재고 = 평균 일일 출고량 × 리드타임 × 안전계수</span></span>
<span class="line"><span>   - 발주점(ROP) = 안전 재고 + (일 평균 소요 × 리드타임)</span></span>
<span class="line"><span>   - 경제적 발주량(EOQ) 산식</span></span>
<span class="line"><span>   - ABC 등급별 차등 기준:</span></span>
<span class="line"><span>     - A: 발주점 도달 즉시 발주, 안전재고 높게</span></span>
<span class="line"><span>     - C: 정기 발주 (주 1회)</span></span>
<span class="line"><span>   - 유통기한 상품: FEFO(선입선출이 아닌 유통기한 임박순 출고)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 시뮬레이션 (가상 데이터)</span></span>
<span class="line"><span>   - 대표 품목 5개로 ROP, 안전재고, EOQ 계산 예시</span></span>
<span class="line"><span>   - 현재 방식 vs 신규 방식 비교 (품절률, 폐기율 예측)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 실사(재고 조사) 절차</span></span>
<span class="line"><span>   - 정기 실사: 월 1회 ABC 등급별 차등</span></span>
<span class="line"><span>   - 순환 실사: A등급 주 1회, B등급 월 2회, C등급 월 1회</span></span>
<span class="line"><span>   - 차이 발생 시 조사 &amp; 보정 절차</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. KPI 대시보드 설계</span></span>
<span class="line"><span>   - 재고 회전율, 품절률, 폐기율, 재고 정확도</span></span>
<span class="line"><span>   - 경보 기준 (빨강/노랑/초록)</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] ABC 분석의 정확한 적용</li><li>[ ] 안전재고/ROP/EOQ 산식의 정확성</li><li>[ ] 유통기한 상품의 FEFO 개념 포함</li><li>[ ] 시뮬레이션의 논리적 일관성</li><li>[ ] 실사 절차의 현실성</li><li>[ ] 품절 30건→감소, 폐기 500만→감소의 예측 근거</li></ul><hr><h2 id="lm-04-물류센터-운영-매뉴얼" tabindex="-1">LM-04. 물류센터 운영 매뉴얼 ⭐⭐⭐ <a class="header-anchor" href="#lm-04-물류센터-운영-매뉴얼" aria-label="Permalink to &quot;LM-04. 물류센터 운영 매뉴얼 :star::star::star:&quot;">​</a></h2><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이커머스 물류센터 운영 매뉴얼을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>물류센터: 약 1,000평, 직원 30명 + 일용직 20명</span></span>
<span class="line"><span>일 처리량: 출고 3,000건, 입고 500건</span></span>
<span class="line"><span>취급 상온/냉장/냉동 3온도대</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/warehouse-operations-manual.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 운영 프로세스 (입고~출고 전체)</span></span>
<span class="line"><span>   - 입고: 검수 → 적치 → 로케이션 등록</span></span>
<span class="line"><span>   - 보관: 온도대별 구역, 로케이션 체계 (A-01-01 형식)</span></span>
<span class="line"><span>   - 주문 수신 → 피킹 → 검품 → 포장 → 출고</span></span>
<span class="line"><span>   - 각 단계: 작업 절차, 소요 시간 기준, 품질 기준</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 레이아웃 설계 원칙</span></span>
<span class="line"><span>   - 입고 도크 → 검수 → 보관 → 피킹 → 포장 → 출고 도크 동선</span></span>
<span class="line"><span>   - ABC 분석 기반 피킹 로케이션 (고빈도 = 가까이)</span></span>
<span class="line"><span>   - 냉장/냉동 구역 위치 및 온도 관리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 일일 운영 스케줄</span></span>
<span class="line"><span>   - 06:00~08:00: 전일 야간 주문 피킹</span></span>
<span class="line"><span>   - 08:00~09:00: 입고 검수</span></span>
<span class="line"><span>   - 09:00~15:00: 주문 처리 (피킹→포장→출고)</span></span>
<span class="line"><span>   - 15:00~16:00: 택배사 픽업</span></span>
<span class="line"><span>   - 16:00~17:00: 정리, 재고 확인</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 품질 관리</span></span>
<span class="line"><span>   - 검수 기준 (입고 시 / 출고 시)</span></span>
<span class="line"><span>   - 오배송률 목표: 0.1% 이하</span></span>
<span class="line"><span>   - 검품 체크리스트 (상품, 수량, 상태, 유통기한)</span></span>
<span class="line"><span>   - 고객 클레임 처리 흐름</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 안전 관리</span></span>
<span class="line"><span>   - 지게차 운행 규칙</span></span>
<span class="line"><span>   - 냉동 구역 작업 시간 제한 (연속 30분 이내)</span></span>
<span class="line"><span>   - 비상 출구, 소화기 위치</span></span>
<span class="line"><span>   - 사고 발생 시 보고 절차</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 인력 관리</span></span>
<span class="line"><span>   - 일용직 교육 (30분 OJT 커리큘럼)</span></span>
<span class="line"><span>   - 성수기 인력 확충 계획 (명절, 11월)</span></span>
<span class="line"><span>   - 생산성 지표 (1인당 시간당 피킹 수)</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 입고~출고 전체 프로세스의 완성도</li><li>[ ] 로케이션 체계 설계의 합리성</li><li>[ ] 3온도대 관리의 현실적 운영</li><li>[ ] 일일 스케줄의 시간 배분</li><li>[ ] 안전 관리의 법적 사항 반영</li><li>[ ] 일용직 OJT의 30분 내 가능한 설계</li><li>[ ] 생산성 지표의 업계 현실성</li></ul><hr><h2 id="lm-05-공급망-리스크-분석" tabindex="-1">LM-05. 공급망 리스크 분석 ⭐⭐⭐ <a class="header-anchor" href="#lm-05-공급망-리스크-분석" aria-label="Permalink to &quot;LM-05. 공급망 리스크 분석 :star::star::star:&quot;">​</a></h2><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>공급망 리스크 분석 보고서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: 전자제품 조립 제조업 (스마트워치)</span></span>
<span class="line"><span>공급망:</span></span>
<span class="line"><span>- Tier 1 (직접 거래): 부품 공급사 8개사</span></span>
<span class="line"><span>  - 배터리: 중국 A사 (점유율 100%, 대체재 없음)</span></span>
<span class="line"><span>  - 디스플레이: 한국 B사 60%, 일본 C사 40%</span></span>
<span class="line"><span>  - 센서: 미국 D사 100%</span></span>
<span class="line"><span>  - PCB: 국내 E사 80%, 베트남 F사 20%</span></span>
<span class="line"><span>  - 케이스: 국내 G사 100%</span></span>
<span class="line"><span>  - 패키징: 국내 H사 100%</span></span>
<span class="line"><span>- 물류: 해상(중국, 일본 부품), 육상(국내)</span></span>
<span class="line"><span>- 리드타임: 중국 3주, 일본 2주, 국내 3~5일</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/supply-chain-risk-analysis.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 공급망 지도</span></span>
<span class="line"><span>   - 전체 공급망 시각화 (텍스트 기반)</span></span>
<span class="line"><span>   - 각 공급사: 위치, 리드타임, 의존도, 대체 가능성</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 리스크 평가 (공급사별)</span></span>
<span class="line"><span>   - 단일 소스 리스크 (배터리 A사, 센서 D사)</span></span>
<span class="line"><span>   - 지정학적 리스크 (중국 배터리: 미중 갈등, 수출 규제)</span></span>
<span class="line"><span>   - 자연재해 리스크 (일본: 지진, 태풍)</span></span>
<span class="line"><span>   - 품질 리스크 (과거 불량 이력)</span></span>
<span class="line"><span>   - 재무 리스크 (공급사 부도 가능성)</span></span>
<span class="line"><span>   - 리스크 매트릭스 (발생확률 × 영향도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 시나리오 분석</span></span>
<span class="line"><span>   - 시나리오 1: 중국 배터리 공급 3개월 중단</span></span>
<span class="line"><span>     - 영향: 전체 생산 중단</span></span>
<span class="line"><span>     - 대응: 대체 공급사 발굴 (한국 배터리 3사 비교)</span></span>
<span class="line"><span>     - 전환 비용 &amp; 기간</span></span>
<span class="line"><span>   - 시나리오 2: 해상 물류 2주 지연 (항만 파업)</span></span>
<span class="line"><span>   - 시나리오 3: 센서 가격 30% 인상 (미국 관세)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 리스크 완화 전략</span></span>
<span class="line"><span>   - 듀얼 소싱 (단일 공급사 → 2사 이상)</span></span>
<span class="line"><span>   - 전략 재고 (핵심 부품 4주분 확보)</span></span>
<span class="line"><span>   - 공급사 다변화 로드맵 (12개월)</span></span>
<span class="line"><span>   - 니어쇼어링 검토 (중국 → 베트남/인도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 모니터링 지표</span></span>
<span class="line"><span>   - 공급사 건전성 스코어카드 (분기별)</span></span>
<span class="line"><span>   - 조기 경보 지표 (리드타임 변동, 불량률 변동, 뉴스 모니터링)</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 단일 소스 리스크의 정확한 식별</li><li>[ ] 지정학적 리스크(미중 갈등)의 현실적 분석</li><li>[ ] 시나리오별 영향 분석의 구체성</li><li>[ ] 듀얼 소싱 전략의 비용/효과 분석</li><li>[ ] 니어쇼어링 검토의 현실성</li><li>[ ] 모니터링 지표의 실용성</li><li>[ ] 전체적으로 SCM 전문가 수준</li></ul><hr><h2 id="lm-06-납품-배송-sla-성과-리포트" tabindex="-1">LM-06. 납품/배송 SLA &amp; 성과 리포트 ⭐ <a class="header-anchor" href="#lm-06-납품-배송-sla-성과-리포트" aria-label="Permalink to &quot;LM-06. 납품/배송 SLA &amp; 성과 리포트 :star:&quot;">​</a></h2><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B2B 고객사와의 납품 SLA 문서와 월간 배송 성과 리포트를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황:</span></span>
<span class="line"><span>- 우리: 산업용 부품 유통업체</span></span>
<span class="line"><span>- 고객: 제조업 10사에 정기 납품</span></span>
<span class="line"><span>- 현재: 납품 지연 클레임 월 5~8건, SLA 문서 없음</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`logistics/delivery-sla.md\` — 납품 SLA 문서</span></span>
<span class="line"><span>   - 표준 납기: 주문 후 3영업일</span></span>
<span class="line"><span>   - 긴급 납기: 주문 후 1영업일 (할증 20%)</span></span>
<span class="line"><span>   - 납기 준수율 목표: 95% 이상</span></span>
<span class="line"><span>   - 미준수 시 패널티:</span></span>
<span class="line"><span>     - 1~3일 지연: 해당 주문 배송비 면제</span></span>
<span class="line"><span>     - 4일 이상: 주문 금액 2% 할인</span></span>
<span class="line"><span>   - 품질 기준: 불량률 0.5% 이하</span></span>
<span class="line"><span>   - 클레임 처리: 접수 후 24시간 내 1차 응답</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`logistics/delivery-performance-report.md\` — 3월 성과 리포트 (가상)</span></span>
<span class="line"><span>   - 총 배송: 450건</span></span>
<span class="line"><span>   - 납기 준수율: 91.3% (목표 미달!)</span></span>
<span class="line"><span>   - 지연 건수: 39건 (평균 지연 1.8일)</span></span>
<span class="line"><span>   - 지연 원인 분석:</span></span>
<span class="line"><span>     - 재고 부족 45%</span></span>
<span class="line"><span>     - 물류사 지연 30%</span></span>
<span class="line"><span>     - 주문 처리 오류 15%</span></span>
<span class="line"><span>     - 기타 10%</span></span>
<span class="line"><span>   - 고객별 납기 준수율 TOP 5 / WORST 5</span></span>
<span class="line"><span>   - 불량 클레임: 3건 (불량률 0.2%, 목표 내)</span></span>
<span class="line"><span>   - 개선 액션 플랜</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] SLA 항목의 적절한 수준 (업계 현실)</li><li>[ ] 패널티 구조의 공정성</li><li>[ ] 성과 리포트의 데이터 기반 분석</li><li>[ ] 지연 원인 분류의 MECE(상호배타적) 여부</li><li>[ ] 고객별 차등 분석</li><li>[ ] 개선 액션의 구체성</li></ul><hr><h2 id="lm-07-원가-절감-공정-개선-제안서" tabindex="-1">LM-07. 원가 절감 &amp; 공정 개선 제안서 ⭐⭐ <a class="header-anchor" href="#lm-07-원가-절감-공정-개선-제안서" aria-label="Permalink to &quot;LM-07. 원가 절감 &amp; 공정 개선 제안서 :star::star:&quot;">​</a></h2><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>제조 라인 원가 절감 제안서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>공장: 자동차 부품 제조 (연 매출 500억, 영업이익률 5%)</span></span>
<span class="line"><span>경영진 지시: &quot;원가 3% 절감하라&quot; (= 연 15억원)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>현재 원가 구조 (제품 1개 기준):</span></span>
<span class="line"><span>- 원재료: 45% (강판, 알루미늄, 플라스틱)</span></span>
<span class="line"><span>- 인건비: 25% (직접 인건비 15%, 간접 10%)</span></span>
<span class="line"><span>- 제조경비: 20% (전기, 설비 감가, 소모품)</span></span>
<span class="line"><span>- 물류비: 5%</span></span>
<span class="line"><span>- 품질 비용: 5% (검사, 불량 폐기, 리워크)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/cost-reduction-proposal.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 현황 분석</span></span>
<span class="line"><span>   - 원가 구조 분해 (파이 차트 형태)</span></span>
<span class="line"><span>   - 업계 벤치마크 대비 (어디가 높은지)</span></span>
<span class="line"><span>   - 최근 3년 원가 추이</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 절감 방안 (10가지 이상)</span></span>
<span class="line"><span>   각 방안:</span></span>
<span class="line"><span>   - 절감 항목, 예상 절감액, 실행 난이도, 투자 필요 여부</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   원재료:</span></span>
<span class="line"><span>   - 대량 구매 협상 (3사→1사 집중, 볼륨 할인)</span></span>
<span class="line"><span>   - 대체 소재 검토 (강판 → 고강도 경량 소재)</span></span>
<span class="line"><span>   - 스크랩률 개선 (현재 8% → 목표 5%)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   인건비:</span></span>
<span class="line"><span>   - 자동화 투자 (용접 로봇 도입 ROI 분석)</span></span>
<span class="line"><span>   - 라인 밸런싱 최적화 (병목 해소)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   제조경비:</span></span>
<span class="line"><span>   - 에너지 절감 (LED 교체, 압축공기 누설 점검)</span></span>
<span class="line"><span>   - 설비 예방정비로 다운타임 감소</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   품질 비용:</span></span>
<span class="line"><span>   - 불량률 감소 (현재 3% → 1.5%)</span></span>
<span class="line"><span>   - 인라인 검사 도입으로 후공정 불량 감소</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 우선순위 매트릭스</span></span>
<span class="line"><span>   - 절감 금액 × 실행 용이성 × 투자 규모</span></span>
<span class="line"><span>   - Quick Win (3개) → 중기 (5개) → 장기 (2개)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 실행 로드맵 (12개월)</span></span>
<span class="line"><span>   - 분기별 목표 절감액</span></span>
<span class="line"><span>   - 투자 대비 회수 기간 (Payback Period)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 리스크</span></span>
<span class="line"><span>   - 품질 저하 없는 원가 절감인지 검증</span></span>
<span class="line"><span>   - 공급사 변경 시 품질 리스크</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 원가 구조 분석의 정확성</li><li>[ ] 10가지 절감 방안의 다양성</li><li>[ ] 자동화 ROI 분석의 현실성</li><li>[ ] 스크랩률/불량률 개선의 구체적 방법</li><li>[ ] 15억원 목표 달성 가능한 조합 제시</li><li>[ ] &quot;품질 저하 없는 절감&quot; 검증 포인트</li><li>[ ] 전체적으로 제조업 원가관리 실무 수준</li></ul><hr><h2 id="lm-08-운송-배차-계획" tabindex="-1">LM-08. 운송 &amp; 배차 계획 ⭐⭐ <a class="header-anchor" href="#lm-08-운송-배차-계획" aria-label="Permalink to &quot;LM-08. 운송 &amp; 배차 계획 :star::star:&quot;">​</a></h2><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>일일 배송 차량 운영 계획을 수립하는 가이드를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: 식자재 유통 (레스토랑/급식 납품)</span></span>
<span class="line"><span>차량: 1톤 냉장차 8대, 3톤 냉장차 4대</span></span>
<span class="line"><span>일일 배송: 약 80건 (서울/수도권)</span></span>
<span class="line"><span>시간 제약: 대부분 오전 6~10시 납품 (레스토랑 영업 전)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`logistics/daily-routing-plan-guide.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 배차 기본 원칙</span></span>
<span class="line"><span>   - 차량별 적재 용량 &amp; 배송 건수 한도</span></span>
<span class="line"><span>   - 지역 클러스터링 (강남, 강북, 경기 서부, 경기 동부...)</span></span>
<span class="line"><span>   - 시간 윈도우 준수 (06:00~10:00 필수 납품)</span></span>
<span class="line"><span>   - 냉장 온도 유지 기준 (0~5도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 배차 절차 (전일 오후)</span></span>
<span class="line"><span>   - D-1 16:00: 익일 주문 마감</span></span>
<span class="line"><span>   - D-1 17:00: 주문 확인 + 피킹 리스트 생성</span></span>
<span class="line"><span>   - D-1 18:00: 배차 계획 수립 (차량별 배정)</span></span>
<span class="line"><span>   - D-1 19:00: 기사 통보 (배송 순서, 고객 정보)</span></span>
<span class="line"><span>   - D-day 05:00: 상차 + 출발</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 배차 최적화 기법</span></span>
<span class="line"><span>   - 지역별 클러스터 → 차량 배정</span></span>
<span class="line"><span>   - 시간 윈도우가 좁은 고객 우선</span></span>
<span class="line"><span>   - 중량/부피 고려 적재 계획</span></span>
<span class="line"><span>   - 복귀 시간 고려 (2차 배송 가능 여부)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 가상 배차 시뮬레이션</span></span>
<span class="line"><span>   - 80건 주문 데이터 (주소, 물량, 시간 요청)</span></span>
<span class="line"><span>   - 12대 차량에 최적 배분 결과</span></span>
<span class="line"><span>   - 차량별: 배송 순서, 예상 시간, 총 주행 거리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 이상 상황 대응</span></span>
<span class="line"><span>   - 차량 고장 시 (대체 차량, 고객 통보)</span></span>
<span class="line"><span>   - 교통 정체 시 (우선순위 재배정)</span></span>
<span class="line"><span>   - 반품/교환 건 처리 (복귀 시 수거)</span></span>
<span class="line"><span>   - 기사 결근 시 (대체 인력, 배차 재편)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. KPI</span></span>
<span class="line"><span>   - 배송 완료율, 시간 준수율, 차량 가동률, 1건당 배송 비용</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 시간 윈도우(06~10시) 제약의 반영</li><li>[ ] 지역 클러스터링의 합리성</li><li>[ ] 적재 계획의 현실성 (중량/부피)</li><li>[ ] 시뮬레이션의 구체성</li><li>[ ] 이상 상황 대응의 현실적 절차</li><li>[ ] KPI의 업계 적합성</li></ul>`,50)])])}const m=n(i,[["render",e]]);export{u as __pageData,m as default};
